from __future__ import annotations

import base64
from pathlib import Path
from typing import Any


DEFENCE_WEBP_BASE64 = (
    ""
)


def install_raid_assets(core: Any) -> None:
    """Создаёт актуальную графическую карту «Защита» для Mini App."""
    if getattr(core, "_raid_assets_v59_installed", False):
        return
    core._raid_assets_v59_installed = True

    target = Path(core.WEBAPP_DIR) / "assets" / "action_defense_v58.webp"
    try:
        payload = base64.b64decode(DEFENCE_WEBP_BASE64, validate=True)
        if not payload.startswith(b"RIFF") or b"WEBP" not in payload[:16]:
            raise RuntimeError("Встроенное изображение защиты не является WebP")
        target.parent.mkdir(parents=True, exist_ok=True)
        target.write_bytes(payload)
    except Exception:
        core.logging.exception("Не удалось подготовить изображение защиты рейда")
